import requests
from saml2.client import SamlClient
from saml2.saml import AuthnRequest

def build_saml_request(destination_url, user_info):
    # Create a SAML client
    client = SamlClient()

    # Set the destination URL
    client.sso_url = destination_url

    # Create an AuthnRequest object
    authn_request = AuthnRequest()

    # Set the user name and password
    authn_request.name_id = user_info["username"]
    authn_request.password = user_info["password"]

    # Encode the SAML request
    saml_xml = client.encode(authn_request)

    # POST the SAML request to the Identity Provider
    requests.post(destination_url, data=saml_xml)